/**
 * routes/adminRoutes.js
 *
 * Single-role admin system — all admins have equal access.
 * No super_admin tier. Invite system remains so new admins
 * can only join via a one-time link generated by an existing admin.
 *
 * Registration: invite token required → account auto-approved (active).
 * Any logged-in admin can manage other admins (approve, suspend, delete).
 */

const { setAuthCookie }    = require("../utils/setCookies");
const ADMIN_COOKIE_MAX_AGE = 2 * 60 * 60 * 1000; // 2 hours

const express    = require("express");
const path       = require("path");
const fs         = require("fs");
const jwt        = require("jsonwebtoken");
const bcrypt     = require("bcrypt");
const { v4: uuidv4 } = require("uuid");
const multer     = require("multer");
const rateLimit  = require("express-rate-limit");

const { requireAdmin }  = require("../middleware/adminAuth");
const Admin             = require("../models/admin");
const AdminInvite       = require("../models/adminInvite");
const Quiz              = require("../models/quiz");
const Question          = require("../models/question");
const QuizCatalog       = require("../models/quizCatalog");
const Child             = require("../models/child");
const Purchase          = require("../models/purchase");
const connectDB         = require("../config/db");

const router     = express.Router();
const JWT_SECRET = process.env.JWT_SECRET || process.env.PARENT_JWT_SECRET;

// ═══════════════════════════════════════════════════════════
// Strict rate limiter for login — 5 attempts / 15 min per IP
// ═══════════════════════════════════════════════════════════
const adminLoginLimiter = rateLimit({
  windowMs:        15 * 60 * 1000,
  max:             5,
  message:         { error: "Too many login attempts. Try again in 15 minutes." },
  standardHeaders: true,
  legacyHeaders:   false,
});

