// ═══════════════════════════════════════════════════════════
// INVITE SYSTEM — any admin can invite a new admin
// ═══════════════════════════════════════════════════════════

// POST /api/admin/invite — generate a one-time invite link
router.post("/invite", async (req, res) => {
  try {
    await connectDB();

    const invite = await AdminInvite.create({
      created_by: req.admin.email,
    });

    const FRONTEND_URL = process.env.FRONTEND_ORIGIN || "http://localhost:5173";
    const invite_url = `${FRONTEND_URL}/#/kai-ops-9281/register?invite=${invite.token}`;

    return res.json({
      ok:         true,
      invite_url,
      expires_in: "24 hours",
      created_by: req.admin.email,
    });
  } catch (err) {
    console.error("Create invite error:", err);
    return res.status(500).json({ error: err.message });
  }
});

// GET /api/admin/invites — list active invites
router.get("/invites", async (req, res) => {
  try {
    await connectDB();
    const invites = await AdminInvite.find({
      used:      false,
      expiresAt: { $gt: new Date() },
    })
      .sort({ createdAt: -1 })
      .select("token created_by createdAt expiresAt")
      .lean();

    const FRONTEND_URL = process.env.FRONTEND_ORIGIN || "http://localhost:5173";

    return res.json(
      invites.map((i) => ({
        ...i,
        invite_url: `${FRONTEND_URL}/#/kai-ops-9281/register?invite=${i.token}`,
      }))
    );
  } catch (err) {
    return res.status(500).json({ error: err.message });
  }
});

// DELETE /api/admin/invites/:token — revoke an invite
router.delete("/invites/:token", async (req, res) => {
  try {
    await connectDB();
    await AdminInvite.deleteOne({ token: req.params.token });
    return res.json({ ok: true });
  } catch (err) {
    return res.status(500).json({ error: err.message });
  }
});

